		SimpleEmitter.EmitStatements(self, block.Statements)
		return
	end
	if kind == 8805 then
		local ret = stmt
		if ret.Expression == nil then
			SimpleEmitter.AppendLine(self, "return")
		else
			SimpleEmitter.AppendLine(self, "return " .. SimpleEmitter.EmitExpression(self, ret.Expression))
		end
		return
	end
	if kind == 8797 then
		local exprStmt = stmt
		local exprText = SimpleEmitter.EmitExpressionStatement(self, exprStmt.Expression)
		SimpleEmitter.AppendLine(self, exprText)
		return
	end
	if kind == 8793 then
		local local = stmt
		local luauType = SimpleEmitter.MapType(self, local.TypeName)
		if self._localCount < 64 then
			self._localNames[self._localCount + 1] = local.VariableName
			self._localTypes[self._localCount + 1] = local.TypeName
			self._localCount = self._localCount + 1
		end
		if local.Initializer ~= nil then
			local init = SimpleEmitter.EmitExpression(self, local.Initializer)
			SimpleEmitter.AppendLine(self, "local " .. local.VariableName .. ": " .. luauType .. " = " .. init)
		else
			SimpleEmitter.AppendLine(self, "local " .. local.VariableName .. ": " .. luauType .. " = " .. SimpleEmitter.DefaultForType(self, local.TypeName))
		end
		return
	end
	if kind == 8802 then
		local ws = stmt
		SimpleEmitter.AppendLine(self, "while " .. SimpleEmitter.EmitExpression(self, ws.Condition) .. " do")
		SimpleEmitter.Indent(self)
		SimpleEmitter.EmitBlockBody(self, ws.Body)
		SimpleEmitter.Dedent(self)
		SimpleEmitter.AppendLine(self, "end")
		return
	end
	if kind == 8811 then
		local fs = stmt
		SimpleEmitter.EmitForStatement(self, fs)
		return
	end
	if kind == 8812 then
		local fes = stmt
		if self._localCount < 64 then
			self._localNames[self._localCount + 1] = fes.Identifier
			self._localTypes[self._localCount + 1] = fes.TypeName
			self._localCount = self._localCount + 1
		end
		SimpleEmitter.AppendLine(self, "for _, " .. fes.Identifier .. " in " .. SimpleEmitter.EmitExpression(self, fes.Expression) .. " do")
		SimpleEmitter.Indent(self)
		SimpleEmitter.EmitBlockBody(self, fes.Body)
		SimpleEmitter.Dedent(self)
		SimpleEmitter.AppendLine(self, "end")
		return
	end
	if kind == 8810 then
		local ds = stmt
		SimpleEmitter.AppendLine(self, "repeat")
		SimpleEmitter.Indent(self)
		SimpleEmitter.EmitBlockBody(self, ds.Body)
		SimpleEmitter.Dedent(self)
		SimpleEmitter.AppendLine(self, "until not (" .. SimpleEmitter.EmitExpression(self, ds.Condition) .. ")")
		return
	end
	if kind == 8821 then
		local ss = stmt
		SimpleEmitter.EmitSwitchStatement(self, ss)
		return
	end
	if kind == 8825 then
		local ts = stmt
		SimpleEmitter.EmitTryStatement(self, ts)
		return
	end
	if kind == 8808 then
		local thr = stmt
		if thr.Expression ~= nil then
			if thr.Expression.Kind == 8649 then
				local obj = thr.Expression
				if #obj.Arguments > 0 then
					SimpleEmitter.AppendLine(self, "error(" .. SimpleEmitter.EmitExpression(self, obj.Arguments[0 + 1]) .. ")")
				else
					SimpleEmitter.AppendLine(self, "error(\"" .. obj.TypeName .. "\")")
				end
			else
				SimpleEmitter.AppendLine(self, "error(" .. SimpleEmitter.EmitExpression(self, thr.Expression) .. ")")
			end
		else
			SimpleEmitter.AppendLine(self, "error(\"re-throw\")")
		end
		return
	end
	stmt:AcceptWalker(self)
end

function SimpleEmitter.VisitIfStatement(self: SimpleEmitter, node: IfStatementSyntax): ()
	SimpleEmitter.AppendLine(self, "if " .. SimpleEmitter.EmitExpression(self, node.Condition) .. " then")
	SimpleEmitter.Indent(self)
	SimpleEmitter.EmitBlockBody(self, node.ThenBody)
	SimpleEmitter.Dedent(self)
	if node.ElseBody ~= nil then
		SimpleEmitter.EmitElseBody(self, node.ElseBody)
	else
		SimpleEmitter.AppendLine(self, "end")
	end
end

function SimpleEmitter.EmitElseBody(self: SimpleEmitter, elseBody: StatementSyntax): ()
	if elseBody == nil then
		SimpleEmitter.AppendLine(self, "end")
		return
	end
	if elseBody.Kind == 8792 then
		SimpleEmitter.AppendLine(self, "else")
		SimpleEmitter.Indent(self)
		local block = elseBody
		SimpleEmitter.EmitStatements(self, block.Statements)
		SimpleEmitter.Dedent(self)
		SimpleEmitter.AppendLine(self, "end")
		return
	end
	if elseBody.Kind == 8819 then
		local elseIf = elseBody
		SimpleEmitter.AppendLine(self, "elseif " .. SimpleEmitter.EmitExpression(self, elseIf.Condition) .. " then")
		SimpleEmitter.Indent(self)
		SimpleEmitter.EmitBlockBody(self, elseIf.ThenBody)
		SimpleEmitter.Dedent(self)
		if elseIf.ElseBody ~= nil then
			SimpleEmitter.EmitElseBody(self, elseIf.ElseBody)
		else
			SimpleEmitter.AppendLine(self, "end")
		end
		return
	end
	SimpleEmitter.AppendLine(self, "else")
	SimpleEmitter.Indent(self)
	SimpleEmitter.EmitStatement(self, elseBody)
	SimpleEmitter.Dedent(self)
	SimpleEmitter.AppendLine(self, "end")
end

function SimpleEmitter.VisitBreakStatement(self: SimpleEmitter, node: BreakStatementSyntax): ()
	SimpleEmitter.AppendLine(self, "break")
end

function SimpleEmitter.VisitContinueStatement(self: SimpleEmitter, node: ContinueStatementSyntax): ()
	SimpleEmitter.AppendLine(self, "continue")
end

function SimpleEmitter.EmitBlockBody(self: SimpleEmitter, body: StatementSyntax): ()
	if body == nil then
		return
	end
	if body.Kind == 8792 then
		local block = body
		SimpleEmitter.EmitStatements(self, block.Statements)
	else
		SimpleEmitter.EmitStatement(self, body)
	end
end

function SimpleEmitter.EmitForStatement(self: SimpleEmitter, fs: ForStatementSyntax): ()
	local isSimpleNumericFor = false
	local varName = ""
	local startVal = ""
	local endExpr = ""
	if fs.Declaration ~= nil and fs.Declaration.Kind == 8793 and fs.Condition ~= nil and #fs.Incrementors == 1 then
		local decl = fs.Declaration
		varName = decl.VariableName
		if decl.Initializer ~= nil then
			startVal = SimpleEmitter.EmitExpression(self, decl.Initializer)
		end
		local condKind = fs.Condition.Kind
		if condKind >= 8668 and condKind <= 8688 then
			local cond = fs.Condition
			local inc = fs.Incrementors[0 + 1]
			local incIsPlus = false
			if inc.Kind == 8738 or inc.Kind == 8739 then
				local post = inc
				if post.OperatorKind == 8440 then
					incIsPlus = true
				end
			elseif inc.Kind == 8734 then
				incIsPlus = true
			end
			if incIsPlus then
				if cond.OperatorToken.Text == "<" then
					endExpr = SimpleEmitter.EmitExpression(self, cond.Right) .. " - 1"
					isSimpleNumericFor = true
				elseif cond.OperatorToken.Text == "<=" then
					endExpr = SimpleEmitter.EmitExpression(self, cond.Right)
					isSimpleNumericFor = true
				end
			end
		end
	end
	if isSimpleNumericFor then
		SimpleEmitter.AppendLine(self, "for " .. varName .. " = " .. startVal .. ", " .. endExpr .. " do")
		SimpleEmitter.Indent(self)
		SimpleEmitter.EmitBlockBody(self, fs.Body)
		SimpleEmitter.Dedent(self)
		SimpleEmitter.AppendLine(self, "end")
	else
		if fs.Declaration ~= nil then
			SimpleEmitter.EmitStatement(self, fs.Declaration)
		end
		local condText = "true"
		if fs.Condition ~= nil then
			condText = SimpleEmitter.EmitExpression(self, fs.Condition)
		end
		SimpleEmitter.AppendLine(self, "while " .. condText .. " do")
		SimpleEmitter.Indent(self)
		SimpleEmitter.EmitBlockBody(self, fs.Body)
		local i = 0
		while i < #fs.Incrementors do
			SimpleEmitter.AppendLine(self, SimpleEmitter.EmitExpressionStatement(self, fs.Incrementors[i + 1]))
			i += 1
		end
		SimpleEmitter.Dedent(self)
		SimpleEmitter.AppendLine(self, "end")
	end
end

function SimpleEmitter.EmitSwitchStatement(self: SimpleEmitter, ss: SwitchStatementSyntax): ()
	local switchExpr = SimpleEmitter.EmitExpression(self, ss.Expression)
	local switchVar = "__switch_val"
	SimpleEmitter.AppendLine(self, "local " .. switchVar .. " = " .. switchExpr)
	local isFirst = true
	local i = 0
	while i < #ss.Sections do
		local section = ss.Sections[i + 1]
		local isDefault = false
		local caseCondition = ""
		local j = 0
		while j < #section.Labels do
			if section.Labels[j + 1] == nil then
				isDefault = true
			else
				local labelExpr = SimpleEmitter.EmitExpression(self, section.Labels[j + 1])
				if #caseCondition > 0 then
					caseCondition = caseCondition .. " or "
				end
				caseCondition = caseCondition .. switchVar .. " == " .. labelExpr
			end
			j += 1
		end
		if isDefault and #caseCondition == 0 then
			if isFirst then
				SimpleEmitter.AppendLine(self, "do")
			else
				SimpleEmitter.AppendLine(self, "else")
			end
		elseif isFirst then
			SimpleEmitter.AppendLine(self, "if " .. caseCondition .. " then")
		else
			SimpleEmitter.AppendLine(self, "elseif " .. caseCondition .. " then")
		end
		SimpleEmitter.Indent(self)
		local j = 0
		while j < #section.Statements do
			if section.Statements[j + 1]:Accept() == "break;" then
				continue
			end
			SimpleEmitter.EmitStatement(self, section.Statements[j + 1])
			j += 1
		end
		SimpleEmitter.Dedent(self)
		isFirst = false
		i += 1
	end
	SimpleEmitter.AppendLine(self, "end")
end

function SimpleEmitter.EmitTryStatement(self: SimpleEmitter, ts: TryStatementSyntax): ()
	local errVar = "__err"
	if #ts.Catches > 0 and ts.Catches[0 + 1].Identifier ~= nil then
		errVar = ts.Catches[0 + 1].Identifier
	end
	SimpleEmitter.AppendLine(self, "local __ok, " .. errVar .. " = pcall(function()")
	SimpleEmitter.Indent(self)
	if ts.Block ~= nil then
		SimpleEmitter.EmitStatements(self, ts.Block.Statements)
	end
	SimpleEmitter.Dedent(self)
	SimpleEmitter.AppendLine(self, "end)")
	if #ts.Catches > 0 then
		SimpleEmitter.AppendLine(self, "if not __ok then")
		SimpleEmitter.Indent(self)
		SimpleEmitter.EmitStatements(self, ts.Catches[0 + 1].Block.Statements)
		SimpleEmitter.Dedent(self)
		SimpleEmitter.AppendLine(self, "end")
	end
	if ts.FinallyBlock ~= nil then
		SimpleEmitter.EmitStatements(self, ts.FinallyBlock.Statements)
	end
end

function SimpleEmitter.EmitExpressionStatement(self: SimpleEmitter, expr: ExpressionSyntax): string
	if expr == nil then
		return ""
	end
	local kind = expr.Kind
	if kind == 8714 then
		local assign = expr
		return SimpleEmitter.EmitExpression(self, assign.Left) .. " = " .. SimpleEmitter.EmitExpression(self, assign.Right)
	end
	if kind == 8715 then
		local assign = expr
		return SimpleEmitter.EmitExpression(self, assign.Left) .. " += " .. SimpleEmitter.EmitExpression(self, assign.Right)
	end
	if kind == 8716 then
		local assign = expr
		return SimpleEmitter.EmitExpression(self, assign.Left) .. " -= " .. SimpleEmitter.EmitExpression(self, assign.Right)
	end
	if kind == 8717 then
		local assign = expr
		return SimpleEmitter.EmitExpression(self, assign.Left) .. " *= " .. SimpleEmitter.EmitExpression(self, assign.Right)
	end
	if kind == 8718 then
		local assign = expr
		return SimpleEmitter.EmitExpression(self, assign.Left) .. " /= " .. SimpleEmitter.EmitExpression(self, assign.Right)
	end
	if kind == 8719 then
		local assign = expr
		return SimpleEmitter.EmitExpression(self, assign.Left) .. " %= " .. SimpleEmitter.EmitExpression(self, assign.Right)
	end
	if kind == 8738 then
		local post = expr
		return SimpleEmitter.EmitExpression(self, post.Operand) .. " += 1"
	end
	if kind == 8739 then
		local post = expr
		return SimpleEmitter.EmitExpression(self, post.Operand) .. " -= 1"
	end
	if kind == 8734 then
		local pre = expr
		return SimpleEmitter.EmitExpression(self, pre.Operand) .. " += 1"
	end
	if kind == 8735 then
		local pre = expr
		return SimpleEmitter.EmitExpression(self, pre.Operand) .. " -= 1"
	end
	return SimpleEmitter.EmitExpression(self, expr)
end

function SimpleEmitter.EmitExpression(self: SimpleEmitter, expr: ExpressionSyntax): string
	if expr == nil then
		return "nil"
	end
	local kind = expr.Kind
	if kind == 8748 then
		return "true"
	end
	if kind == 8749 then
		return "false"
	end
	if kind == 8754 then
		return "nil"
	end
	if kind == 8753 then
		return "nil"
	end
	if kind == 8750 then
		local lit = expr
		local text = lit.Token.Text
		if #text > 0 then
			local last = string.byte(text, #text - 1 + 1)
			if last == 102 or last == 70 or last == 100 or last == 68 or last == 109 or last == 77 or last == 76 or last == 108 or last == 117 or last == 85 then
				text = string.sub(text, 0 + 1, 0 + #text - 1)
			end
		end
		return text
	end
	if kind == 8751 then
		local lit = expr
		return lit.Token.Text
	end
	if kind == 8752 then
		local lit = expr
		local charText = lit.Token.Text
		if #charText >= 3 and charText[0 + 1] == 39 and charText[#charText - 1 + 1] == 39 then
			local inner = string.sub(charText, 1 + 1, 1 + #charText - 2)
			if inner == "\\n" then
				return "10"
			end
			if inner == "\\r" then
				return "13"
			end
			if inner == "\\t" then
				return "9"
			end
			if inner == "\\\\" then
				return "92"
			end
			if inner == "\\'" then
				return "39"
			end
			if inner == "\\\"" then
				return "34"
			end
			if inner == "\\0" then
				return "0"
			end
			if #inner == 1 then
				return "string.byte(\"" .. inner .. "\", 1)"
			end
		end
		return "string.byte(" .. charText .. ", 1)"
	end
	if kind == 8616 then
		local ident = expr
		local name = ident.Identifier.Text
		if name == "null" then
			return "nil"
		end
		if name == "true" then
			return "true"
		end
		if name == "false" then
			return "false"
		end
		if name == "this" then
			return "self"
		end
		if not self._isStaticContext and #self._currentClassName > 0 then
			local i = 0
			while i < self._fieldCount do
				if self._fieldNames[i + 1] == name then
					return "self." .. name
				end
				i += 1
			end
		end
		return name
	end
	if kind == 8632 then
		local paren = expr
		return "(" .. SimpleEmitter.EmitExpression(self, paren.Expression) .. ")"
	end
	if kind >= 8668 and kind <= 8688 then
		return SimpleEmitter.EmitBinary(self, expr)
	end
	if kind == 8657 then
		local bin = expr
		return "true --[[is " .. SimpleEmitter.EmitExpression(self, bin.Right) .. "]]"
	end
	if kind == 8658 then
		local bin = expr
		return SimpleEmitter.EmitExpression(self, bin.Left)
	end
	if kind == 8730 or kind == 8731 or kind == 8733 then
		local pre = expr
		local opText = pre.OperatorToken.Text
		if opText == "!" then
			return "not " .. SimpleEmitter.EmitExpression(self, pre.Operand)
		end
		if opText == "-" then
			return "-" .. SimpleEmitter.EmitExpression(self, pre.Operand)
		end
		return opText + SimpleEmitter.EmitExpression(self, pre.Operand)
	end
	if kind == 8734 then
		local pre = expr
		return SimpleEmitter.EmitExpression(self, pre.Operand) .. " + 1"
	end
	if kind == 8735 then
		local pre = expr
		return SimpleEmitter.EmitExpression(self, pre.Operand) .. " - 1"
	end
	if kind == 8738 or kind == 8739 then
		local post = expr
		return SimpleEmitter.EmitExpression(self, post.Operand)
	end
	if kind >= 8714 and kind <= 8726 then
		return SimpleEmitter.EmitAssignment(self, expr)
	end
	if kind == 8689 then
		return SimpleEmitter.EmitMemberAccess(self, expr)
	end
	if kind == 8634 then
		return SimpleEmitter.EmitInvocation(self, expr)
	end
	if kind == 8649 then
		return SimpleEmitter.EmitObjectCreation(self, expr)
	end
	if kind == 8635 then
		return SimpleEmitter.EmitElementAccess(self, expr)
	end
	if kind == 8640 then
		local cast = expr
		return SimpleEmitter.EmitExpression(self, cast.Expression)
	end
	if kind == 8643 then
		return SimpleEmitter.EmitLambda(self, expr)
	end
	if kind == 8633 then
		local cond = expr
		return "if " .. SimpleEmitter.EmitExpression(self, cond.Condition) .. " then " .. SimpleEmitter.EmitExpression(self, cond.WhenTrue) .. " else " .. SimpleEmitter.EmitExpression(self, cond.WhenFalse)
	end
	if kind == 9023 then
		return SimpleEmitter.EmitSwitchExpression(self, expr)
	end
	return "nil --[[unknown expr kind " .. SimpleEmitter.IntToString(self, kind) .. "]]"
end

function SimpleEmitter.EmitBinary(self: SimpleEmitter, expr: ExpressionSyntax): string
	local bin = expr
	local left = SimpleEmitter.EmitExpression(self, bin.Left)
	local right = SimpleEmitter.EmitExpression(self, bin.Right)
	local op = bin.OperatorToken.Text
	if op == "!=" then
		return left .. " ~= " .. right
	end
	if op == "&&" then
		return left .. " and " .. right
	end
	if op == "||" then
		return left .. " or " .. right
	end
	if op == "??" then
		return "if " .. left .. " ~= nil then " .. left .. " else " .. right
	end
	if op == "+" then
		local isStringConcat = false
		if bin.Left.Kind == 8751 then
			isStringConcat = true
		end
		if bin.Right.Kind == 8751 then
			isStringConcat = true
		end
		if SimpleEmitter.ContainsConcatOp(self, left) then
			isStringConcat = true
		end
		if SimpleEmitter.ContainsConcatOp(self, right) then
			isStringConcat = true
		end
		if bin.Left.Kind >= 8668 and bin.Left.Kind <= 8688 then
			if SimpleEmitter.HasStringLiteralInChain(self, bin.Left) then
				isStringConcat = true
			end
		end
		if bin.Right.Kind >= 8668 and bin.Right.Kind <= 8688 then
			if SimpleEmitter.HasStringLiteralInChain(self, bin.Right) then
				isStringConcat = true
			end
		end
		if not isStringConcat and SimpleEmitter.HasStringTypedOperand(self, bin.Left) then
			isStringConcat = true
		end
		if not isStringConcat and SimpleEmitter.HasStringTypedOperand(self, bin.Right) then
			isStringConcat = true
		end
		if isStringConcat then
			local lVal = SimpleEmitter.WrapCharForConcat(self, bin.Left, left)
			local rVal = SimpleEmitter.WrapCharForConcat(self, bin.Right, right)
			return lVal .. " .. " .. rVal
		end
	end
	if op == "/" then
		if SimpleEmitter.IsIntegerExpression(self, bin.Left) and SimpleEmitter.IsIntegerExpression(self, bin.Right) then
			return left .. " // " .. right
		end
	end
	if op == "&" then
		return "bit32.band(" .. left .. ", " .. right .. ")"
	end
	if op == "|" then
		return "bit32.bor(" .. left .. ", " .. right .. ")"
	end
	if op == "^" then
		return "bit32.bxor(" .. left .. ", " .. right .. ")"
	end
	if op == "<<" then
		return "bit32.lshift(" .. left .. ", " .. right .. ")"
	end
	if op == ">>" then
		return "bit32.rshift(" .. left .. ", " .. right .. ")"
	end
	return left .. " " .. op .. " " .. right
end

function SimpleEmitter.HasStringLiteralInChain(self: SimpleEmitter, expr: ExpressionSyntax): boolean
	if expr.Kind == 8751 then
		return true
	end
	if expr.Kind >= 8668 and expr.Kind <= 8688 then
		local bin = expr
		if bin.OperatorToken.Text == "+" then
			if SimpleEmitter.HasStringLiteralInChain(self, bin.Left) then
				return true
			end
			if SimpleEmitter.HasStringLiteralInChain(self, bin.Right) then
				return true
			end
		end
	end
	return false
end

function SimpleEmitter.ContainsConcatOp(self: SimpleEmitter, emitted: string): boolean
	local idx = 0
	while idx <= #emitted - 4 do
		if emitted[idx + 1] == 32 and emitted[idx + 1 + 1] == 46 and emitted[idx + 2 + 1] == 46 and emitted[idx + 3 + 1] == 32 then
			return true
		end
		idx += 1
	end
	return false
end

function SimpleEmitter.HasStringTypedOperand(self: SimpleEmitter, expr: ExpressionSyntax): boolean
	if expr.Kind == 8616 then
		local id = expr
		local name = id.Identifier.Text
		local varType = SimpleEmitter.GetVariableType(self, name)
		if varType ~= nil then
			return SimpleEmitter.IsStringType(self, varType)
		end
		if not self._isStaticContext then
			local fieldType = SimpleEmitter.GetFieldType(self, name)
			if fieldType ~= nil then
				return SimpleEmitter.IsStringType(self, fieldType)
			end
		end
	end
	return false
end

function SimpleEmitter.IsIntegerType(self: SimpleEmitter, typeName: string): boolean
	if typeName == nil then
		return false
	end
	if typeName == "int" then
		return true
	end
	if typeName == "long" then
		return true
	end
	if typeName == "short" then
		return true
	end
	if typeName == "byte" then
		return true
	end
	if typeName == "sbyte" then
		return true
	end
	if typeName == "ushort" then
		return true
	end
	if typeName == "uint" then
		return true
	end
	if typeName == "ulong" then
		return true
	end
	if typeName == "char" then
		return true
	end
	return false
end

function SimpleEmitter.IsIntegerExpression(self: SimpleEmitter, expr: ExpressionSyntax): boolean
	if expr.Kind == 8750 then
		return true
	end
	if expr.Kind == 8616 then
		local id = expr
		local name = id.Identifier.Text
		local varType = SimpleEmitter.GetVariableType(self, name)
		if varType ~= nil then
			return SimpleEmitter.IsIntegerType(self, varType)
		end
		if not self._isStaticContext then
			local fieldType = SimpleEmitter.GetFieldType(self, name)
			if fieldType ~= nil then
				return SimpleEmitter.IsIntegerType(self, fieldType)
			end
		end
	end
	if expr.Kind >= 8668 and expr.Kind <= 8688 then
		local bin = expr
		local op = bin.OperatorToken.Text
		if op == "+" or op == "-" or op == "*" or op == "/" or op == "%" then
			return SimpleEmitter.IsIntegerExpression(self, bin.Left) and SimpleEmitter.IsIntegerExpression(self, bin.Right)
		end
	end
	return false
end

function SimpleEmitter.IsCharTypedExpression(self: SimpleEmitter, expr: ExpressionSyntax): boolean
	if expr.Kind == 8616 then
		local id = expr
		local name = id.Identifier.Text
		local varType = SimpleEmitter.GetVariableType(self, name)
		if varType == "char" then
			return true
		end
	end
	return false
end

function SimpleEmitter.WrapCharForConcat(self: SimpleEmitter, expr: ExpressionSyntax, emitted: string): string
	if expr.Kind == 8752 then
		return "string.char(" .. emitted .. ")"
	end
	if SimpleEmitter.IsCharTypedExpression(self, expr) then
		return "string.char(" .. emitted .. ")"
	end
	if expr.Kind == 8640 then
		local cast = expr
		if cast.TypeName == "char" then
			return "string.char(" .. emitted .. ")"
		end
	end
	return emitted
end

function SimpleEmitter.EmitAssignment(self: SimpleEmitter, expr: ExpressionSyntax): string
	local assign = expr
	local left = SimpleEmitter.EmitExpression(self, assign.Left)
	local right = SimpleEmitter.EmitExpression(self, assign.Right)
	local kind = expr.Kind
	if kind == 8714 then
		return left .. " = " .. right
	end
	if kind == 8715 then
		if assign.Right.Kind == 8751 then
			return left .. " ..= " .. right
		end
		if assign.Right.Kind >= 8668 and assign.Right.Kind <= 8688 then
			if SimpleEmitter.HasStringLiteralInChain(self, assign.Right) then
				return left .. " ..= " .. right
			end
		end
		if SimpleEmitter.ContainsConcatOp(self, right) then
			return left .. " ..= " .. right
		end
		return left .. " += " .. right
	end
	if kind == 8716 then
		return left .. " -= " .. right
	end
	if kind == 8717 then
		return left .. " *= " .. right
	end
	if kind == 8718 then
		return left .. " /= " .. right
	end
	if kind == 8719 then
		return left .. " %= " .. right
	end
	return left .. " = " .. right
end

function SimpleEmitter.EmitMemberAccess(self: SimpleEmitter, expr: ExpressionSyntax): string
	local ma = expr
	local memberName = ma.Name.Text
	local obj = SimpleEmitter.EmitExpression(self, ma.Expression)
	if memberName == "Length" or memberName == "Count" then
		return "#" .. obj
	end
	if obj == "Console" and memberName == "WriteLine" then
		return "print"
	end
	if obj == "Console" and memberName == "Write" then
		return "print"
	end
	if obj == "Math" then
		local luauMath = SimpleEmitter.MapMathMember(self, memberName)
		if luauMath ~= nil then
			return luauMath
		end
	end
	if obj == "string" and memberName == "Empty" then
		return "\"\""
	end
	if obj == "this" or obj == "self" then
		return "self." .. memberName
	end
	if obj == "base" then
		if self._baseClassName ~= nil then
			return self._baseClassName .. "." .. memberName
		end
		return self._currentClassName .. "." .. memberName
	end
	return obj .. "." .. memberName
end

function SimpleEmitter.MapMathMember(self: SimpleEmitter, member: string): string
	if member == "Max" then
		return "math.max"
	end
	if member == "Min" then
		return "math.min"
	end
	if member == "Abs" then
		return "math.abs"
	end
	if member == "Floor" then
		return "math.floor"
	end
	if member == "Ceiling" then
		return "math.ceil"
	end
	if member == "Round" then
		return "math.round"
	end
	if member == "Sqrt" then
		return "math.sqrt"
	end
	if member == "Pow" then
		return "math.pow"
	end
	if member == "Log" then
		return "math.log"
	end
	if member == "PI" then
		return "math.pi"
	end
	if member == "E" then
		return "math.exp(1)"
	end
	return nil
end

function SimpleEmitter.IsInstanceMethod(self: SimpleEmitter, name: string): boolean
	local i = 0
	while i < self._methodCount do
		if self._methodNames[i + 1] == name and not self._isMethodStatic[i + 1] then
			return true
		end
		i += 1
	end
	return false
end

function SimpleEmitter.IsStaticMethod(self: SimpleEmitter, name: string): boolean
	local i = 0
	while i < self._methodCount do
		if self._methodNames[i + 1] == name and self._isMethodStatic[i + 1] then
			return true
		end
		i += 1
	end
	return false
end

function SimpleEmitter.IsKnownVariable(self: SimpleEmitter, name: string): boolean
	local i = 0
	while i < self._paramCount do
		if self._paramNames[i + 1] == name then
			return true
		end
		i += 1
	end
	local i = 0
	while i < self._localCount do
		if self._localNames[i + 1] == name then
			return true
		end
		i += 1
	end
	return false
end

function SimpleEmitter.IsInstanceCallTarget(self: SimpleEmitter, target: ExpressionSyntax, emittedObj: string): boolean
	if emittedObj == "self" then
		return true
	end
	if #emittedObj > 5 and string.sub(emittedObj, 0 + 1, 0 + 5) == "self." then
		return true
	end
	if target.Kind == 8690 then
		return true
	end
	if target.Kind == 8616 then
		local id = target
		if SimpleEmitter.IsKnownVariable(self, id.Identifier.Text) then
			return true
		end
	end
	if target.Kind == 8689 then
		local inner = target
		if inner.Expression.Kind == 8616 then
			local leftId = inner.Expression
			if SimpleEmitter.IsKnownVariable(self, leftId.Identifier.Text) then
				return true
			end
		end
		if inner.Expression.Kind == 8616 then
			local leftId2 = inner.Expression
			if leftId2.Identifier.Text == "self" or leftId2.Identifier.Text == "this" then
				return true
			end
		end
	end
	return false
end

function SimpleEmitter.EmitInvocation(self: SimpleEmitter, expr: ExpressionSyntax): string
	local inv = expr
	local args = ""
	local i = 0
	while i < #inv.Arguments do
		if i > 0 then
			args = args .. ", "
		end
		args = args + SimpleEmitter.EmitExpression(self, inv.Arguments[i + 1])
		i += 1
	end
	if inv.Expression.Kind == 8689 then
		local ma = inv.Expression
		local methodName = ma.Name.Text
		local obj = SimpleEmitter.EmitExpression(self, ma.Expression)
		if obj == "Console" and (methodName == "WriteLine" or methodName == "Write") then
			return "print(" .. args .. ")"
		end
		if obj == "string" and methodName == "IsNullOrEmpty" then
			return "(" .. args .. " == nil or #" .. args .. " == 0)"
		end
		if methodName == "Append" then
			return obj .. " = " .. obj .. " .. " .. args
		end
		if methodName == "AppendLine" then
			if #args > 0 then
				return obj .. " = " .. obj .. " .. " .. args .. " .. \"\\n\""
			end
			return obj .. " = " .. obj .. " .. \"\\n\""
		end
		if methodName == "ToString" and #inv.Arguments == 0 then
			return "tostring(" .. obj .. ")"
		end
		if methodName == "Add" then
			return "table.insert(" .. obj .. ", " .. args .. ")"
		end
		if methodName == "Clear" then
			return "table.clear(" .. obj .. ")"
		end
		if methodName == "Contains" then
			return "table.find(" .. obj .. ", " .. args .. ") ~= nil"
		end
		if methodName == "Insert" then
			return "table.insert(" .. obj .. ", " .. args .. ")"
		end
		if methodName == "RemoveAt" then
			return "table.remove(" .. obj .. ", " .. args .. " + 1)"
		end
		if methodName == "Substring" then
			if #inv.Arguments == 1 then
				return "string.sub(" .. obj .. ", " .. args .. " + 1)"
			end
			if #inv.Arguments == 2 then
				local start = SimpleEmitter.EmitExpression(self, inv.Arguments[0 + 1])
				local len = SimpleEmitter.EmitExpression(self, inv.Arguments[1 + 1])
				return "string.sub(" .. obj .. ", " .. start .. " + 1, " .. start .. " + " .. len .. ")"
			end
		end
		if methodName == "IndexOf" then
			local findArg = args
			if #inv.Arguments == 1 and inv.Arguments[0 + 1].Kind == 8752 then
				findArg = "string.char(" .. args .. ")"
			end
			return "(string.find(" .. obj .. ", " .. findArg .. ", 1, true) or 0) - 1"
		end
		if methodName == "StartsWith" then
			return "string.sub(" .. obj .. ", 1, #" .. args .. ") == " .. args
		end
		if methodName == "EndsWith" then
			return "string.sub(" .. obj .. ", -#" .. args .. ") == " .. args
		end
		if methodName == "Trim" then
			return "string.match(" .. obj .. ", \"^%s*(.-)%s*$\")"
		end
		if methodName == "ToLower" then
			return "string.lower(" .. obj .. ")"
		end
		if methodName == "ToUpper" then
			return "string.upper(" .. obj .. ")"
		end
		if methodName == "Replace" then
			return "string.gsub(" .. obj .. ", " .. args .. ")"
		end
		if obj == "base" and self._baseClassName ~= nil then
			if #args > 0 then
				return self._baseClassName .. "." .. methodName .. "(self, " .. args .. ")"
			end
			return self._baseClassName .. "." .. methodName .. "(self)"
		end
		if SimpleEmitter.IsInstanceCallTarget(self, ma.Expression, obj) then
			return obj .. ":" .. methodName .. "(" .. args .. ")"
		end
		return obj .. "." .. methodName .. "(" .. args .. ")"
	end
	if inv.Expression.Kind == 8616 then
		local calleeId = inv.Expression
		local methodName = calleeId.Identifier.Text
		if not self._isStaticContext and #self._currentClassName > 0 and SimpleEmitter.IsInstanceMethod(self, methodName) then
			if #args > 0 then
				return self._currentClassName .. "." .. methodName .. "(self, " .. args .. ")"
			end
			return self._currentClassName .. "." .. methodName .. "(self)"
		end
		if #self._currentClassName > 0 and SimpleEmitter.IsStaticMethod(self, methodName) then
			return self._currentClassName .. "." .. methodName .. "(" .. args .. ")"
		end
	end
	local callee = SimpleEmitter.EmitExpression(self, inv.Expression)
	return callee .. "(" .. args .. ")"
end

function SimpleEmitter.EmitObjectCreation(self: SimpleEmitter, expr: ExpressionSyntax): string
	local obj = expr
	local args = ""
	local i = 0
	while i < #obj.Arguments do
		if i > 0 then
			args = args .. ", "
		end
		args = args + SimpleEmitter.EmitExpression(self, obj.Arguments[i + 1])
		i += 1
	end
	local typeName = obj.TypeName
	if typeName == "StringBuilder" then
		return "\"\""
	end
	if #typeName > 5 and string.sub(typeName, 0 + 1, 0 + 5) == "List<" then
		return "{}"
	end
	if #typeName > 11 and string.sub(typeName, 0 + 1, 0 + 11) == "Dictionary<" then
		return "{}"
	end
	if #typeName > 8 and string.sub(typeName, 0 + 1, 0 + 8) == "HashSet<" then
		return "{}"
	end
	if typeName == "Exception" or typeName == "InvalidOperationException" or typeName == "ArgumentException" or typeName == "ArgumentNullException" or typeName == "NotImplementedException" or typeName == "NotSupportedException" or typeName == "IndexOutOfRangeException" or typeName == "OverflowException" then
		if #obj.Arguments > 0 then
			return SimpleEmitter.EmitExpression(self, obj.Arguments[0 + 1])
		end
		return "\"" .. typeName .. "\""
	end
	if #obj.Initializers > 0 then
		local iife = "(function() local __obj = " .. typeName .. ".new(" .. args .. "); "
		local i = 0
		while i < #obj.Initializers do
			local fieldName = SimpleEmitter.EmitExpression(self, obj.Initializers[i + 1].Left)
			local fieldVal = SimpleEmitter.EmitExpression(self, obj.Initializers[i + 1].Right)
			iife = iife .. "__obj." .. fieldName .. " = " .. fieldVal .. "; "
			i += 1
		end
		iife = iife .. "return __obj end)()"
		return iife
	end
	return typeName .. ".new(" .. args .. ")"
end

function SimpleEmitter.GetVariableType(self: SimpleEmitter, name: string): string
	local i = 0
	while i < self._paramCount do
		if self._paramNames[i + 1] == name then
			return self._paramTypes[i + 1]
		end
		i += 1
	end
	local i = 0
	while i < self._localCount do
		if self._localNames[i + 1] == name then
			return self._localTypes[i + 1]
		end
		i += 1
	end
	return nil
end

function SimpleEmitter.IsStringType(self: SimpleEmitter, typeName: string): boolean
	if typeName == nil then
		return false
	end
	if typeName == "string" then
		return true
	end
	if typeName == "String" then
		return true
	end
	return false
end

function SimpleEmitter.GetFieldType(self: SimpleEmitter, fieldName: string): string
	local i = 0
	while i < self._fieldCount do
		if self._fieldNames[i + 1] == fieldName then
			return self._fieldTypes[i + 1]
		end
		i += 1
	end
	return nil
end

function SimpleEmitter.IsStringExpression(self: SimpleEmitter, expr: ExpressionSyntax): boolean
	if expr.Kind == 8616 then
		local id = expr
		local name = id.Identifier.Text
		local varType = SimpleEmitter.GetVariableType(self, name)
		if varType ~= nil then
			return SimpleEmitter.IsStringType(self, varType)
		end
		if not self._isStaticContext then
			local fieldType = SimpleEmitter.GetFieldType(self, name)
			if fieldType ~= nil then
				return SimpleEmitter.IsStringType(self, fieldType)
			end
		end
	end
	if expr.Kind == 8689 then
		local ma = expr
		if ma.Expression.Kind == 8616 then
			local leftId = ma.Expression
			local leftName = leftId.Identifier.Text
			if leftName == "this" or leftName == "self" then
				local fieldType = SimpleEmitter.GetFieldType(self, ma.Name.Text)
				if fieldType ~= nil then
					return SimpleEmitter.IsStringType(self, fieldType)
				end
			end
		end
	end
	return false
end

function SimpleEmitter.EmitElementAccess(self: SimpleEmitter, expr: ExpressionSyntax): string
	local ea = expr
	local obj = SimpleEmitter.EmitExpression(self, ea.Expression)
	local index = SimpleEmitter.EmitExpression(self, ea.Index)
	local isStringIndex = SimpleEmitter.IsStringExpression(self, ea.Expression)
	if isStringIndex then
		if ea.Index.Kind == 8750 then
			local lit = ea.Index
			local numText = lit.Token.Text
			local numVal = 0
			local isSimple = true
			local i = 0
			while i < #numText do
				local c = numText[i + 1]
				if c >= 48 and c <= 57 then
					numVal = numVal * 10 + (c - 48)
				else
					isSimple = false
				end
				i += 1
			end
			if isSimple then
				return "string.byte(" .. obj .. ", " .. SimpleEmitter.IntToString(self, numVal .. 1) .. ")"
			end
		end
		return "string.byte(" .. obj .. ", " .. index .. " + 1)"
	end
	if ea.Index.Kind == 8750 then
		local lit = ea.Index
		local numText = lit.Token.Text
		local numVal = 0
		local isSimple = true
		local i = 0
		while i < #numText do
			local c = numText[i + 1]
			if c >= 48 and c <= 57 then
				numVal = numVal * 10 + (c - 48)
			else
				isSimple = false
			end
			i += 1
		end
		if isSimple then
			return obj .. "[" .. SimpleEmitter.IntToString(self, numVal .. 1) .. "]"
		end
	end
	return obj .. "[" .. index .. " + 1]"
end

function SimpleEmitter.EmitLambda(self: SimpleEmitter, expr: ExpressionSyntax): string
	local lam = expr
	local parms = ""
	local i = 0
	while i < #lam.ParameterNames do
		if i > 0 then
			parms = parms .. ", "
		end
		parms = parms + lam.ParameterNames[i + 1]
		i += 1
	end
	if lam.ExpressionBody ~= nil then
		return "function(" .. parms .. ") return " .. SimpleEmitter.EmitExpression(self, lam.ExpressionBody) .. " end"
	end
	if lam.BlockBody ~= nil then
		local savedOutput = self._output
		local savedIndent = self._indent
		self._output = ""
		self._indent = 0
		SimpleEmitter.EmitBlockBody(self, lam.BlockBody)
		local body = self._output
		self._output = savedOutput
		self._indent = savedIndent
		if #body > 0 and body[#body - 1 + 1] == 10 then
			body = string.sub(body, 0 + 1, 0 + #body - 1)
		end
		return "function(" .. parms .. ")\n" .. body .. "\nend"
	end
	return "function(" .. parms .. ") end"
end

function SimpleEmitter.EmitSwitchExpression(self: SimpleEmitter, expr: ExpressionSyntax): string
	local sw = expr
	local govExpr = SimpleEmitter.EmitExpression(self, sw.GoverningExpression)
	local result = ""
	local i = 0
	while i < #sw.Arms do
		local arm = sw.Arms[i + 1]
		local armExpr = SimpleEmitter.EmitExpression(self, arm.Expression)
		if arm.Pattern == nil then
			if #result == 0 then
				result = armExpr
			else
				result = result .. " else " .. armExpr
			end
		else
			local patternExpr = SimpleEmitter.EmitExpression(self, arm.Pattern)
			if #result == 0 then
				result = "if " .. govExpr .. " == " .. patternExpr .. " then " .. armExpr
			else
				result = result .. " elseif " .. govExpr .. " == " .. patternExpr .. " then " .. armExpr
			end
		end
		i += 1
	end
	return result
end

function SimpleEmitter.IntToString(self: SimpleEmitter, value: number): string
	if value == 0 then
		return "0"
	end
	local negative = false
	if value < 0 then
		negative = true
		value = -value
	end
	local result = ""
	local n = value
	while n > 0 do
		local digit = n % 10
		local c = (48 + digit)
		result = c + result
		n = n / 10
	end
	if negative then
		result = "-" .. result
	end
	return result
end

return { SimpleEmitter = SimpleEmitter }
